proof fn phi_1_singleton_seq_to_set_len<T>(x: T)
    ensures
        seq![x].to_set().len() == 1,
{
    singleton_seq_to_set_is_singleton_set(x);
    assert(seq![x].to_set() == set![x]);
    assert(set![x].len() == 1);
}

proof fn phi_2_singleton_seq_to_set_contains_only_element<T>(x: T, y: T)
    requires
        seq![x].to_set().contains(y),
    ensures
        x == y,
{
    singleton_seq_to_set_is_singleton_set(x);
    assert(set![x].contains(y));
}

proof fn phi_3_empty_seq_to_set_is_empty()
    ensures
        Seq::<int>::empty().to_set() == Set::<int>::empty(),
{
    assert_sets_equal!(Seq::<int>::empty().to_set(), Set::<int>::empty());
}

proof fn phi_4_duplicate_seq_to_set_equals_singleton(x: int)
    ensures
        seq![x, x].to_set() == set![x],
{
    let s = seq![x, x];
    let ts = s.to_set();
    assert(s[0] == x);
    assert(s[1] == x);
    assert forall |y| ts.contains(y) <==> set![x].contains(y) by {
        if ts.contains(y) {
            assert(exists|i: int| 0 <= i < s.len() && s[i] == y);
        }
    }
    assert_sets_equal!(ts, set![x]);
}

proof fn phi_5_seq_to_set_subset_of_push(s: Seq<int>, x: int)
    ensures
        s.to_set().subset_of(s.push(x).to_set()),
{
    let s2 = s.push(x);
    assert forall |y| s.to_set().contains(y) implies s2.to_set().contains(y) by {
        let i = choose|i: int| 0 <= i < s.len() && s[i] == y;
        assert(s2[i] == y);
    }
}
